adaptability.onModifySTAB:
onModifySTAB(stab, source, target, move) {
            if (move.forceSTAB || source.hasType(move.type)) {
                if (stab === 2) {
                    return 2.25;
                }
                return 2;
            }
        }

aerilate.onModifyType:
onModifyType(move, pokemon) {
            const noModifyType = [
                'judgment', 'multiattack', 'naturalgift', 'revelationdance', 'technoblast', 'terrainpulse', 'weatherball',
            ];
            if (move.type === 'Normal' && (!noModifyType.includes(move.id) || this.activeMove?.isMax) &&
                !(move.isZ && move.category !== 'Status') && !(move.name === 'Tera Blast' && pokemon.terastallized)) {
                move.type = 'Flying';
                move.typeChangerBoosted = this.effect;
            }
        }

aerilate.onBasePower:
onBasePower(basePower, pokemon, target, move) {
            if (move.typeChangerBoosted === this.effect)
                return this.chainModify([4915, 4096]);
        }

aftermath.onDamagingHit:
onDamagingHit(damage, target, source, move) {
            if (!target.hp && this.checkMoveMakesContact(move, source, target, true)) {
                this.damage(source.baseMaxhp / 4, source, target);
            }
        }

airlock.onSwitchIn:
onSwitchIn(pokemon) {
            // Air Lock does not activate when Skill Swapped or when Neutralizing Gas leaves the field
            this.add('-ability', pokemon, 'Air Lock');
            this.effect.onStart.call(this, pokemon);
        }

airlock.onStart:
onStart(pokemon) {
            pokemon.abilityState.ending = false; // Clear the ending flag
            this.eachEvent('WeatherChange', this.effect);
        }

analytic.onBasePower:
onBasePower(basePower, pokemon) {
            let boosted = true;
            for (const target of this.getAllActive()) {
                if (target === pokemon)
                    continue;
                if (this.queue.willMove(target)) {
                    boosted = false;
                    break;
                }
            }
            if (boosted) {
                this.debug('Analytic boost');
                return this.chainModify([5325, 4096]);
            }
        }

angerpoint.onHit:
onHit(target, source, move) {
            if (!target.hp)
                return;
            if (move?.effectType === 'Move' && target.getMoveHitData(move).crit) {
                this.boost({ atk: 12 }, target, target);
            }
        }

angershell.onDamage:
onDamage(damage, target, source, effect) {
            this.effectState.checkedAngerShell = !(effect.effectType === "Move" && !effect.multihit &&
                !(effect.hasSheerForce && source.hasAbility('sheerforce')));
        }

angershell.onTryEatItem:
onTryEatItem(item) {
            const healingItems = [
                'aguavberry', 'enigmaberry', 'figyberry', 'iapapaberry', 'magoberry', 'sitrusberry', 'wikiberry', 'oranberry', 'berryjuice',
            ];
            if (healingItems.includes(item.id)) {
                return this.effectState.checkedAngerShell;
            }
            return true;
        }

angershell.onAfterMoveSecondary:
onAfterMoveSecondary(target, source, move) {
            this.effectState.checkedAngerShell = true;
            if (!source || source === target || !target.hp || !move.totalDamage)
                return;
            const lastAttackedBy = target.getLastAttackedBy();
            if (!lastAttackedBy)
                return;
            const damage = move.multihit ? move.totalDamage : lastAttackedBy.damage;
            if (target.hp <= target.maxhp / 2 && target.hp + damage > target.maxhp / 2) {
                this.boost({ atk: 1, spa: 1, spe: 1, def: -1, spd: -1 }, target, target);
            }
        }

anticipation.onStart:
onStart(pokemon) {
            for (const target of pokemon.foes()) {
                for (const moveSlot of target.moveSlots) {
                    const move = this.dex.moves.get(moveSlot.move);
                    if (move.category === 'Status')
                        continue;
                    const moveType = move.id === 'hiddenpower' ? target.hpType : move.type;
                    if (this.dex.getImmunity(moveType, pokemon) && this.dex.getEffectiveness(moveType, pokemon) > 0 ||
                        move.ohko) {
                        this.add('-ability', pokemon, 'Anticipation');
                        return;
                    }
                }
            }
        }

arenatrap.onFoeMaybeTrapPokemon:
onFoeMaybeTrapPokemon(pokemon, source) {
            if (!source)
                source = this.effectState.target;
            if (!source || !pokemon.isAdjacent(source))
                return;
            if (pokemon.isGrounded(!pokemon.knownType)) { // Negate immunity if the type is unknown
                pokemon.maybeTrapped = true;
            }
        }

armortail.onFoeTryMove:
onFoeTryMove(target, source, move) {
            const targetAllExceptions = ['perishsong', 'flowershield', 'rototiller'];
            if (move.target === 'foeSide' || (move.target === 'all' && !targetAllExceptions.includes(move.id))) {
                return;
            }
            const armorTailHolder = this.effectState.target;
            if ((source.isAlly(armorTailHolder) || move.target === 'all') && move.priority > 0.1) {
                this.attrLastMove('[still]');
                this.add('cant', armorTailHolder, 'ability: Armor Tail', move, `[of] ${target}`);
                return false;
            }
        }

