commander.onUpdate:
onUpdate(pokemon) {
            if (this.gameType !== 'doubles')
                return;
            // don't run between when a Pokemon switches in and the resulting onSwitchIn event
            if (this.queue.peek()?.choice === 'runSwitch')
                return;
            const ally = pokemon.allies()[0];
            if (pokemon.switchFlag || ally?.switchFlag)
                return;
            if (!ally || pokemon.baseSpecies.baseSpecies !== 'Tatsugiri' || ally.baseSpecies.baseSpecies !== 'Dondozo') {
                // Handle any edge cases
                if (pokemon.getVolatile('commanding'))
                    pokemon.removeVolatile('commanding');
                return;
            }
            if (!pokemon.getVolatile('commanding')) {
                // If Dondozo already was commanded this fails
                if (ally.getVolatile('commanded'))
                    return;
                // Cancel all actions this turn for pokemon if applicable
                this.queue.cancelAction(pokemon);
                // Add volatiles to both pokemon
                this.add('-activate', pokemon, 'ability: Commander', `[of] ${ally}`);
                pokemon.addVolatile('commanding');
                ally.addVolatile('commanded', pokemon);
                // Continued in conditions.ts in the volatiles
            }
            else {
                if (!ally.fainted)
                    return;
                pokemon.removeVolatile('commanding');
            }
        }

competitive.onAfterEachBoost:
onAfterEachBoost(boost, target, source, effect) {
            if (!source || target.isAlly(source)) {
                return;
            }
            let statsLowered = false;
            let i;
            for (i in boost) {
                if (boost[i] < 0) {
                    statsLowered = true;
                }
            }
            if (statsLowered) {
                this.boost({ spa: 2 }, target, target, null, false, true);
            }
        }

