orichalcumpulse.onStart:
onStart(pokemon) {
            if (this.field.setWeather('sunnyday')) {
                this.add('-activate', pokemon, 'Orichalcum Pulse', '[source]');
            }
            else if (this.field.isWeather('sunnyday')) {
                this.add('-activate', pokemon, 'ability: Orichalcum Pulse');
            }
        }

orichalcumpulse.onModifyAtk:
onModifyAtk(atk, pokemon) {
            if (['sunnyday', 'desolateland'].includes(pokemon.effectiveWeather())) {
                this.debug('Orichalcum boost');
                return this.chainModify([5461, 4096]);
            }
        }

overcoat.onImmunity:
onImmunity(type, pokemon) {
            if (type === 'sandstorm' || type === 'hail' || type === 'powder')
                return false;
        }

overcoat.onTryHit:
onTryHit(target, source, move) {
            if (move.flags['powder'] && target !== source && this.dex.getImmunity('powder', target)) {
                this.add('-immune', target, '[from] ability: Overcoat');
                return null;
            }
        }

overgrow.onModifyAtk:
onModifyAtk(atk, attacker, defender, move) {
            if (move.type === 'Grass' && attacker.hp <= attacker.maxhp / 3) {
                this.debug('Overgrow boost');
                return this.chainModify(1.5);
            }
        }

overgrow.onModifySpA:
onModifySpA(atk, attacker, defender, move) {
            if (move.type === 'Grass' && attacker.hp <= attacker.maxhp / 3) {
                this.debug('Overgrow boost');
                return this.chainModify(1.5);
            }
        }

owntempo.onUpdate:
onUpdate(pokemon) {
            if (pokemon.volatiles['confusion']) {
                this.add('-activate', pokemon, 'ability: Own Tempo');
                pokemon.removeVolatile('confusion');
            }
        }

owntempo.onHit:
onHit(target, source, move) {
            if (move?.volatileStatus === 'confusion') {
                this.add('-immune', target, 'confusion', '[from] ability: Own Tempo');
            }
        }

owntempo.onTryBoost:
onTryBoost(boost, target, source, effect) {
            if (effect.name === 'Intimidate' && boost.atk) {
                delete boost.atk;
                this.add('-fail', target, 'unboost', 'Attack', '[from] ability: Own Tempo', `[of] ${target}`);
            }
        }

parentalbond.onPrepareHit:
onPrepareHit(source, target, move) {
            if (move.category === 'Status' || move.multihit || move.flags['noparentalbond'] || move.flags['charge'] ||
                move.flags['futuremove'] || move.spreadHit || move.isZ || move.isMax)
                return;
            move.multihit = 2;
            move.multihitType = 'parentalbond';
        }

parentalbond.onSourceModifySecondaries:
onSourceModifySecondaries(secondaries, target, source, move) {
            if (move.multihitType === 'parentalbond' && move.id === 'secretpower' && move.hit < 2) {
                // hack to prevent accidentally suppressing King's Rock/Razor Fang
                return secondaries.filter(effect => effect.volatileStatus === 'flinch');
            }
        }

pastelveil.onStart:
onStart(pokemon) {
            for (const ally of pokemon.alliesAndSelf()) {
                if (['psn', 'tox'].includes(ally.status)) {
                    this.add('-activate', pokemon, 'ability: Pastel Veil');
                    ally.cureStatus();
                }
            }
        }

pastelveil.onUpdate:
onUpdate(pokemon) {
            if (['psn', 'tox'].includes(pokemon.status)) {
                this.add('-activate', pokemon, 'ability: Pastel Veil');
                pokemon.cureStatus();
            }
        }

pastelveil.onSetStatus:
onSetStatus(status, target, source, effect) {
            if (!['psn', 'tox'].includes(status.id))
                return;
            if (effect?.status) {
                this.add('-immune', target, '[from] ability: Pastel Veil');
            }
            return false;
        }

pastelveil.onAllySetStatus:
onAllySetStatus(status, target, source, effect) {
            if (!['psn', 'tox'].includes(status.id))
                return;
            if (effect?.status) {
                const effectHolder = this.effectState.target;
                this.add('-block', target, 'ability: Pastel Veil', `[of] ${effectHolder}`);
            }
            return false;
        }

perishbody.onDamagingHit:
onDamagingHit(damage, target, source, move) {
            if (!this.checkMoveMakesContact(move, source, target) || source.volatiles['perishsong'])
                return;
            this.add('-ability', target, 'Perish Body');
            source.addVolatile('perishsong');
            target.addVolatile('perishsong');
        }

pickpocket.onAfterMoveSecondary:
onAfterMoveSecondary(target, source, move) {
            if (source && source !== target && move?.flags['contact']) {
                if (target.item || target.switchFlag || target.forceSwitchFlag || source.switchFlag === true) {
                    return;
                }
                const yourItem = source.takeItem(target);
                if (!yourItem) {
                    return;
                }
                if (!target.setItem(yourItem)) {
                    source.item = yourItem.id;
                    return;
                }
                this.add('-enditem', source, yourItem, '[silent]', '[from] ability: Pickpocket', `[of] ${source}`);
                this.add('-item', target, yourItem, '[from] ability: Pickpocket', `[of] ${source}`);
            }
        }

pickup.onResidual:
onResidual(pokemon) {
            if (pokemon.item)
                return;
            const pickupTargets = this.getAllActive().filter(target => (target.lastItem && target.usedItemThisTurn && pokemon.isAdjacent(target)));
            if (!pickupTargets.length)
                return;
            const randomTarget = this.sample(pickupTargets);
            const item = randomTarget.lastItem;
            randomTarget.lastItem = '';
            this.add('-item', pokemon, this.dex.items.get(item), '[from] ability: Pickup');
            pokemon.setItem(item);
        }

piercingdrill.onHitProtect:
onHitProtect(source, target, move) {
            if (move.flags['contact']) {
                target.getMoveHitData(move).bypassProtect = this.effect;
                return false;
            }
        }

pixilate.onModifyType:
onModifyType(move, pokemon) {
            const noModifyType = [
                'judgment', 'multiattack', 'naturalgift', 'revelationdance', 'technoblast', 'terrainpulse', 'weatherball',
            ];
            if (move.type === 'Normal' && (!noModifyType.includes(move.id) || this.activeMove?.isMax) &&
                !(move.isZ && move.category !== 'Status') && !(move.name === 'Tera Blast' && pokemon.terastallized)) {
                move.type = 'Fairy';
                move.typeChangerBoosted = this.effect;
            }
        }

pixilate.onBasePower:
onBasePower(basePower, pokemon, target, move) {
            if (move.typeChangerBoosted === this.effect)
                return this.chainModify([4915, 4096]);
        }

plus.onModifySpA:
onModifySpA(spa, pokemon) {
            for (const allyActive of pokemon.allies()) {
                if (allyActive.hasAbility(['minus', 'plus'])) {
                    return this.chainModify(1.5);
                }
            }
        }

poisonheal.onDamage:
onDamage(damage, target, source, effect) {
            if (effect.id === 'psn' || effect.id === 'tox') {
                this.heal(target.baseMaxhp / 8);
                return false;
            }
        }

poisonpoint.onDamagingHit:
onDamagingHit(damage, target, source, move) {
            if (this.checkMoveMakesContact(move, source, target)) {
                if (this.randomChance(3, 10)) {
                    source.trySetStatus('psn', target);
                }
            }
        }

poisonpuppeteer.onAnyAfterSetStatus:
onAnyAfterSetStatus(status, target, source, effect) {
            if (source.baseSpecies.name !== "Pecharunt")
                return;
            if (source !== this.effectState.target || target === source || effect.effectType !== 'Move')
                return;
            if (status.id === 'psn' || status.id === 'tox') {
                target.addVolatile('confusion');
            }
        }

poisontouch.onSourceDamagingHit:
onSourceDamagingHit(damage, target, source, move) {
            // Despite not being a secondary, Shield Dust / Covert Cloak block Poison Touch's effect
            if (target.hasAbility('shielddust') || target.hasItem('covertcloak'))
                return;
            if (this.checkMoveMakesContact(move, target, source)) {
                if (this.randomChance(3, 10)) {
                    target.trySetStatus('psn', source);
                }
            }
        }

powerconstruct.onResidual:
onResidual(pokemon) {
            if (pokemon.baseSpecies.baseSpecies !== 'Zygarde' || pokemon.transformed || !pokemon.hp)
                return;
            if (pokemon.species.id === 'zygardecomplete' || pokemon.hp > pokemon.maxhp / 2)
                return;
            this.add('-activate', pokemon, 'ability: Power Construct');
            pokemon.formeChange('Zygarde-Complete', this.effect, true);
            pokemon.canMegaEvo = pokemon.canMegaEvo === false ? false : this.actions.canMegaEvo(pokemon);
            pokemon.formeRegression = true;
        }

powerofalchemy.onAllyFaint:
onAllyFaint(target) {
            if (!this.effectState.target.hp)
                return;
            const ability = target.getAbility();
            if (ability.flags['noreceiver'] || ability.id === 'noability')
                return;
            this.effectState.target.setAbility(ability, target);
        }

powerspot.onAllyBasePower:
onAllyBasePower(basePower, attacker, defender, move) {
            if (attacker !== this.effectState.target) {
                this.debug('Power Spot boost');
                return this.chainModify([5325, 4096]);
            }
        }

prankster.onModifyPriority:
onModifyPriority(priority, pokemon, target, move) {
            if (move?.category === 'Status') {
                move.pranksterBoosted = true;
                return priority + 1;
            }
        }

primordialsea.onAnySetWeather:
onAnySetWeather(target, source, weather) {
            const strongWeathers = ['desolateland', 'primordialsea', 'deltastream'];
            if (this.field.getWeather().id === 'primordialsea' && !strongWeathers.includes(weather.id))
                return false;
        }

primordialsea.onEnd:
onEnd(pokemon) {
            if (this.field.weatherState.source !== pokemon)
                return;
            for (const target of this.getAllActive()) {
                if (target === pokemon)
                    continue;
                if (target.hasAbility('primordialsea')) {
                    this.field.weatherState.source = target;
                    return;
                }
            }
            this.field.clearWeather();
        }

prismarmor.onSourceModifyDamage:
onSourceModifyDamage(damage, source, target, move) {
            if (target.getMoveHitData(move).typeMod > 0) {
                this.debug('Prism Armor neutralize');
                return this.chainModify(0.75);
            }
        }

propellertail.onModifyMove:
onModifyMove(move) {
            // most of the implementation is in Battle#getTarget
            move.tracksTarget = move.target !== 'scripted';
        }

protean.onPrepareHit:
onPrepareHit(source, target, move) {
            if (this.effectState.protean)
                return;
            if (move.hasBounced || move.flags['futuremove'] || move.sourceEffect === 'snatch' || move.callsMove)
                return;
            const type = move.type;
            if (type && type !== '???' && source.getTypes().join() !== type) {
                if (!source.setType(type))
                    return;
                this.effectState.protean = true;
                this.add('-start', source, 'typechange', type, '[from] ability: Protean');
            }
        }

protosynthesis.onWeatherChange:
