            if (this.field.isWeather('sunnyday')) {
                pokemon.addVolatile('protosynthesis');
            }
            else if (!pokemon.volatiles['protosynthesis']?.fromBooster && !this.field.isWeather('sunnyday')) {
                pokemon.removeVolatile('protosynthesis');
