                this.add('-activate', pokemon, 'ability: Quick Draw');
                return 0.1;
            }
        }

raindish.onWeather:
onWeather(target, source, effect) {
            if (target.effectiveWeather() !== effect.id)
                return;
            if (effect.id === 'raindance' || effect.id === 'primordialsea') {
                this.heal(target.baseMaxhp / 16);
