sandveil.onModifyAccuracy:
onModifyAccuracy(accuracy) {
            if (typeof accuracy !== 'number')
                return;
            if (this.field.isWeather('sandstorm')) {
                this.debug('Sand Veil - decreasing accuracy');
                return this.chainModify([3277, 4096]);
            }
