sapsipper.onTryHit:
onTryHit(target, source, move) {
            if (target !== source && move.type === 'Grass') {
                if (!this.boost({ atk: 1 })) {
                    this.add('-immune', target, '[from] ability: Sap Sipper');
                }
                return null;
            }
        }

sapsipper.onAllyTryHitSide:
onAllyTryHitSide(target, source, move) {
            if (source === this.effectState.target || !target.isAlly(source))
                return;
            if (move.type === 'Grass') {
                this.boost({ atk: 1 }, this.effectState.target);
            }
        }

schooling.onStart:
onStart(pokemon) {
            if (pokemon.baseSpecies.baseSpecies !== 'Wishiwashi' || pokemon.level < 20 || pokemon.transformed)
                return;
            if (pokemon.hp > pokemon.maxhp / 4) {
                if (pokemon.species.id === 'wishiwashi') {
                    pokemon.formeChange('Wishiwashi-School');
                }
            }
            else {
                if (pokemon.species.id === 'wishiwashischool') {
                    pokemon.formeChange('Wishiwashi');
                }
            }
        }

schooling.onResidual:
onResidual(pokemon) {
            if (pokemon.baseSpecies.baseSpecies !== 'Wishiwashi' || pokemon.level < 20 ||
                pokemon.transformed || !pokemon.hp)
                return;
            if (pokemon.hp > pokemon.maxhp / 4) {
                if (pokemon.species.id === 'wishiwashi') {
                    pokemon.formeChange('Wishiwashi-School');
                }
            }
            else {
                if (pokemon.species.id === 'wishiwashischool') {
                    pokemon.formeChange('Wishiwashi');
                }
            }
        }

scrappy.onModifyMove:
onModifyMove(move) {
            if (!move.ignoreImmunity)
                move.ignoreImmunity = {};
            if (move.ignoreImmunity !== true) {
                move.ignoreImmunity['Fighting'] = true;
                move.ignoreImmunity['Normal'] = true;
            }
        }

scrappy.onTryBoost:
onTryBoost(boost, target, source, effect) {
            if (effect.name === 'Intimidate' && boost.atk) {
                delete boost.atk;
                this.add('-fail', target, 'unboost', 'Attack', '[from] ability: Scrappy', `[of] ${target}`);
            }
        }

screencleaner.onStart:
onStart(pokemon) {
            let activated = false;
            for (const sideCondition of ['reflect', 'lightscreen', 'auroraveil']) {
                for (const side of [pokemon.side, ...pokemon.side.foeSidesWithConditions()]) {
                    if (side.getSideCondition(sideCondition)) {
                        if (!activated) {
                            this.add('-activate', pokemon, 'ability: Screen Cleaner');
                            activated = true;
                        }
                        side.removeSideCondition(sideCondition);
                    }
                }
